import java.io.File;
import java.io.FileReader;
import java.io.IOException;

public class PathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../confidentialFiles/secret.txt"; // User input with path traversal attempt

        String directory = "/var/www/public/"; // Base directory where files should be accessed from
        String fullPath = directory + userInput; // Construct full path by appending user input

        try {
            File file = new File(fullPath);
            FileReader fr = new FileReader(file);

            int data;
            while ((data = fr.read()) != -1) {
                System.out.print((char) data);
            }

            fr.close();
        } catch (IOException e) {
            System.out.println("Error accessing file: " + e.getMessage());
        }
    }
}

